-- Enrichment marathon batch: Rank Math, Rapid7, Rask AI, Ravio, Ray, Raygun, Rclone, Re:amaze

-- ── Rank Math ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WordPress SEO plugin offering on-page optimization, schema markup, sitemaps, and AI-assisted content tools$q$, short_description),
  pricing_model = COALESCE($q$Freemium - free WordPress.org plugin plus paid Pro, Business, and Agency subscription tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free plugin available; Pro starts around $8.99/month (billed annually, renews at that rate) or roughly $59/year$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Approximately 26 employees, fully remote team$q$, company_size),
  headquarters = COALESCE($q$New Delhi, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Rank Math Review 2026 - Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Rank Math is a WordPress SEO plugin with schema markup, rank tracking, and AI content tools. See 2026 pricing, features, pros and cons before you buy.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rank Math is a WordPress search engine optimization plugin first launched in 2018 by a development team associated with MyThemeShop and headquartered in New Delhi, India. The company operates as a fully remote team of roughly two dozen people and has grown into one of the most widely installed SEO plugins in the WordPress ecosystem, competing directly with Yoast SEO and All in One SEO. Rank Math follows a freemium business model: a free version is distributed through the official WordPress.org plugin repository and includes on-page SEO analysis, Google Search Console integration inside the WordPress dashboard, XML sitemap generation, and support for 18 predefined schema types for rich snippets. Paid Rank Math Pro plans unlock additional capabilities such as an Advanced Rank Tracker, a broken link checker, automated internal keyword linking, a free trial of the separate Content AI writing assistant, and support for more websites and tracked keywords. Pricing is tiered by use case: the Pro plan targets individual bloggers and solopreneurs with unlimited personal websites and tracking for 500 keywords; the Business plan is aimed at freelancers and small agencies, supporting around 100 client websites and 10,000 tracked keywords; and the Agency plan scales to roughly 500 client websites and 50,000 tracked keywords with priority support. All paid plans are billed annually with a stated discount off the regular renewal rate, and the company offers a 30-day money-back guarantee. Core functionality includes a real-time SEO score and content analysis as content is written, structured data (schema) generation for articles, products, FAQs, recipes, local businesses, and more, redirection and 404 monitoring tools, a dedicated WooCommerce SEO module for online stores, and a Local SEO module for businesses managing Google Business Profile-style structured data. Rank Math also provides a built-in importer that can migrate settings and metadata directly from competing plugins such as Yoast SEO and All in One SEO, which lowers the switching cost for site owners evaluating alternatives. Because it runs entirely inside the WordPress admin dashboard, Rank Math does not require a separate SaaS login for its core SEO features, though the optional Content AI writing tool operates on its own credit-based subscription. The plugin is best suited to WordPress site owners, bloggers, ecommerce merchants using WooCommerce, and small-to-midsize agencies managing multiple client sites who want a single tool covering technical SEO, structured data, and keyword tracking without stitching together several separate plugins.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c0b93c88-b6a7-4966-a55f-54c933658952';

