-- ── Rapid7 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Publicly traded cybersecurity company providing vulnerability management, cloud security, SIEM/XDR, and managed detection and response$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise quote-based pricing, typically licensed per asset or per user; no self-serve public pricing$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed - pricing requires contacting Rapid7 sales$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$Approximately 2,500-3,300 employees (varies by source and reporting date); publicly traded (NASDAQ: RPD)$q$, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Rapid7 Review 2026 - Products, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Rapid7 is a Boston-based cybersecurity company offering vulnerability management, SIEM/XDR, and managed detection and response. See products, pricing notes, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rapid7 is a publicly traded cybersecurity company founded in Boston, Massachusetts in July 2000 by Alan Matthews, Tas Giakouminakis, and Chad Loder. The company trades on NASDAQ under the ticker RPD and remains headquartered in Boston, with employee counts reported in the 2,500 to 3,300 range depending on the source and reporting period. Rapid7 describes itself as a global leader in AI-powered managed cybersecurity operations, and its unifying product is the Rapid7 Command Platform, which integrates security telemetry across an organization's attack surface, enriches it with threat intelligence and AI, and feeds it into detection, response, and exposure management workflows. The company's product portfolio spans several major categories. On the exposure and vulnerability management side, Rapid7 offers InsightVM and the legacy Nexpose product line for identifying, prioritizing, and remediating vulnerabilities across on-premises and cloud assets, along with Attack Surface Management (ASM) capabilities for continuously discovering internet-facing exposure. On the detection and response side, InsightIDR functions as a next-generation SIEM and XDR platform, correlating logs, endpoint data, and network telemetry to detect threats, and Rapid7 layers a Managed Detection and Response (MDR) service on top, providing a 24/7 security operations center staffed by Rapid7 analysts for organizations that want outsourced monitoring and response. Cloud-native application protection is handled by InsightCloudSec, and application security testing is covered by InsightAppSec, a dynamic application security testing (DAST) tool. Rapid7 also maintains a Threat Intelligence offering and application security consulting, penetration testing, and IoT security testing services. The company is closely associated with two widely known open-source security projects: Metasploit, the penetration testing framework used broadly across the offensive security community, and Velociraptor, an open-source endpoint monitoring and digital forensics tool, both of which Rapid7 maintains and uses to build credibility and community goodwill among security practitioners. Rapid7 reports serving more than 11,500 customers worldwide, ranging from mid-market businesses to large enterprises, and positions itself against competitors such as Tenable, Qualys, CrowdStrike, and Splunk depending on the specific product category. Because Rapid7 sells to enterprise and mid-market security teams, pricing is not published on its website and is instead quoted individually based on the number of assets, users, or the specific combination of Insight Platform modules an organization licenses; prospective customers typically need to request a demo or quote directly from Rapid7's sales team to get pricing. The platform is best suited for IT and security teams that need a single vendor covering vulnerability management, detection and response, and cloud security, or organizations that want to outsource day-to-day security monitoring to a managed SOC rather than staffing one internally.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '13b772a5-dcc4-4861-96b2-092a5abf26bb';

