-- ── Ravio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Real-time compensation benchmarking and pay data platform for global tech and growth-stage companies$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise SaaS subscription; pricing not publicly disclosed, requires contacting sales$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed - custom quote based on company size and modules$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Estimated 50-90 employees (LinkedIn lists an 11-50 band; other data providers estimate closer to 90 as of 2025)$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Ravio Review 2026 - Compensation Benchmarking Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Ravio is a real-time compensation benchmarking platform for tech companies, covering 46+ countries. See 2026 features, funding, and pricing notes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Ravio is a London-based compensation intelligence platform founded in 2022 to modernize how fast-growing technology companies benchmark salary and equity data. Rather than relying on static, once-a-year compensation surveys, Ravio built a real-time data model: client companies connect their HR information systems (HRIS) to Ravio in a give-to-get arrangement, contributing anonymized compensation data in exchange for access to continuously updated market benchmarks. The platform reports coverage across more than 46 countries and 100-plus roles, which is particularly relevant for European and international tech companies that need pay data spanning multiple labor markets rather than a single country's averages. Ravio's co-CEOs are Roy Blanga and Merten Wulfert, both previously managers at Deliveroo, alongside additional co-founders; the company has scaled its headcount into the tens to roughly one hundred employees depending on the data source and reporting date. In May 2025, Ravio announced a 12 million dollar Series A funding round led by US-based Spark Capital, with participation from Blackbird (Australia) and Cherry Ventures (Europe), funding that the company said would go toward expanding its live benchmarking data and product further. Beyond raw benchmarking data, Ravio's platform includes tools for building compensation bands and pay architecture, running pay equity analysis to identify unexplained pay gaps, generating total rewards statements for employees, and providing reporting and analytics dashboards for people and total rewards teams. Because Ravio's compensation data is refreshed through live HRIS integrations rather than periodic manual surveys, the company positions this as more accurate and timely than legacy compensation survey providers, particularly for fast-scaling companies where roles, levels, and pay bands change frequently. Ravio does not publish self-serve pricing; access requires contacting the company's sales team, and pricing is understood to scale with company size, the modules licensed (benchmarking, banding, pay equity, and so on), and the number of HR system integrations required. The platform is best suited for People, Total Rewards, and HR leadership teams at venture-backed technology and growth-stage companies operating across multiple countries who need current market data to set competitive pay ranges, and for finance leaders who need defensible, up-to-date compensation benchmarks for budgeting and board reporting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '240f9156-e0ab-42ca-b567-928a9cab1bb2';

