-- ── Raygun ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Application performance monitoring, crash reporting, and real user monitoring platform for web and mobile apps$q$, short_description),
  pricing_model = COALESCE($q$Usage-based subscription tiers sold per product (Crash Reporting, APM, Real User Monitoring), with an annual billing discount$q$, pricing_model),
  starting_price = COALESCE($q$From $40/month (billed annually) for the Crash Reporting Basic plan, covering up to 100,000 errors per month$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (mid-size private company with offices in Wellington, New Zealand and Seattle, United States)$q$, company_size),
  headquarters = COALESCE($q$Wellington, New Zealand, with an additional office in Seattle, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Raygun Review 2026 - APM and Crash Reporting Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Raygun is an application performance monitoring and crash reporting platform. See 2026 pricing for Crash Reporting, APM, and Real User Monitoring plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Raygun is an application performance monitoring, crash reporting, and real user monitoring platform founded by John-Daniel Trask and Jeremy Boyd, who started their original company (originally called Mindscape, alongside co-founder Andrew Peters) in Wellington, New Zealand in 2007. The Raygun product name and brand were adopted in 2013 when the founders decided their developer tools business needed a more memorable identity, and the company has operated as Raygun since. Raygun is headquartered in Wellington, New Zealand, with an additional office in Seattle, United States, reflecting its dual presence in the Australasian and North American markets. The platform's core purpose is to help software teams detect, diagnose, and resolve issues in production applications by combining three connected products: Crash Reporting, which pinpoints the root cause of errors and intelligently prioritizes them by the number of affected users rather than raw error count, supports virtually any language or framework via lightweight SDKs, and tracks both client-side and server-side errors across desktop and mobile apps; Application Performance Monitoring (APM), which provides server-side performance visibility through visual flame charts showing full trace capture with method-level timing precision, identifying exactly which functions ran, how long they took, and where a slow request originated; and Real User Monitoring (RUM), which tracks actual front-end performance across real user sessions, offering waterfall timeline visualizations, Core Web Vitals and UX metrics, and the ability to filter performance data by browser, geography, device, or application version, and to correlate user experience with engineering events like deployments. Raygun sells these three products on separate usage-based pricing tracks, each scaling by monthly volume, errors for Crash Reporting, sessions for Real User Monitoring, and traces for APM, with tiers named Basic, Team, Business, and a custom Enterprise tier. Annual billing offers roughly a third off the equivalent monthly rate across all three products, and every tier includes unlimited applications, unlimited team members, and a 14-day free trial. Higher tiers add features like inbound filters and third-party integrations at the Team level, and SAML single sign-on plus dedicated account management at the Business level. Raygun is commonly used by software development and DevOps teams that need to combine error tracking with performance diagnostics in a single platform rather than operating separate crash-reporting and APM tools, and it is positioned as a competitor to tools such as Sentry, New Relic, and Datadog in different parts of its product line.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '64fcba47-1f37-4b44-92d6-1d4880760b16';

