-- ── Re:amaze ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered customer service helpdesk and live chat platform built for ecommerce and online businesses$q$, short_description),
  pricing_model = COALESCE($q$Per-user monthly subscription tiers, plus a flat-rate/volume-based plan option, with an annual billing discount$q$, pricing_model),
  starting_price = COALESCE($q$$29/user/month (billed monthly), or $59/month flat-rate Starter plan for unlimited users capped at 500 conversations/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not publicly disclosed; operates under GoDaddy ownership per current company listings$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Re:amaze Review 2026 - Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Re:amaze is an AI-powered helpdesk and live chat platform for ecommerce businesses. See 2026 pricing plans, features, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Re:amaze is a customer service helpdesk and live chat platform founded in 2012 and headquartered in San Jose, California, built specifically for ecommerce and online businesses. Current company listings show Re:amaze operating under GoDaddy, indicating it has become part of GoDaddy's business software portfolio, though it continues to be marketed and sold as Re:amaze. The platform positions itself as an AI-powered customer service and AI agent platform, unifying multiple support channels, email, live chat, social media, mobile SMS, VoIP calling, video calls, and push notifications, into a single shared inbox so support teams can manage every customer conversation from one place regardless of channel. Verified customers referenced in Re:amaze's own marketing include Printful, a print-on-demand ecommerce company, BuiltBar, a food and beverage ecommerce brand, and Moviepilot, a media platform serving more than 30 million users, illustrating its use both in direct ecommerce and in content/media businesses with high support volume. Re:amaze's product includes a Re:amaze AI Agent that automates common customer resolutions, workflow automation and chatbot tools for routing and answering routine questions, a public and internal FAQ knowledge base, and, on higher tiers, features like multi-brand management for companies running several storefronts under one support team, live visitor view for watching real-time site activity, in-chat screensharing through a feature called Peek, department and staff shift management, custom staff roles, and customer satisfaction ratings. Pricing is structured per team member across three named tiers, Basic at 29 dollars per user per month, Pro at 49 dollars per user per month, and Plus at 69 dollars per user per month, each roughly 10 percent cheaper when billed annually, plus a flat-rate Starter plan at 59 dollars per month that includes Basic-tier features for an unlimited number of team members but caps usage at 500 resolved conversations per month. The Basic and Plus tiers each include a monthly allotment of AI-powered resolutions handled by the Re:amaze AI Agent (5 per user on Basic, 20 per user on Plus), with additional AI resolutions beyond that allotment billed at 85 cents each. All plans include a 14-day free trial that unlocks Plus-tier features for evaluation, and Re:amaze advertises no long-term contracts, allowing month-to-month billing and cancellation. Re:amaze is widely distributed through the Shopify App Store as a helpdesk and live chat app, reflecting its strong focus on ecommerce merchants, and it competes with other ecommerce-focused support tools such as Gorgias. It is best suited for online retailers and ecommerce brands, particularly Shopify merchants, that need to centralize support across chat, email, and social channels and want built-in AI automation for routine customer questions, rather than for large enterprises with highly complex, multi-department support operations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7a3094cf-a8e5-4f7e-b9ed-7fe69416116b';

